	fa(i, 1, n)cin >> a[i];

	var f = [&](int type)->int {
		var nex = vector<int>(n + 2, n); // i 的下一个关键点
		var mark = vector<bool>(n + 1);  // i 是否为关键点

		fb(i, n - 1, 1) {
			if (type == 0) {
				// 谷 峰 谷
				if (i & 1) {
					if (a[i] >= a[i + 1]) {
						// 不满足构造条件
						if (mark[i + 2])nex[i] = i + 2;
						else nex[i] = nex[i + 2];
						mark[i] = 1;
					}
					else {
						// 满足构造条件
						if (mark[i + 1])nex[i] = i + 1;
						else nex[i] = nex[i + 1];
					}
				}
				else {
					if (a[i] > a[i + 1]) {
						// 满足构造条件
						if (mark[i + 1])nex[i] = i + 1;
						else nex[i] = nex[i + 1];
					}
					else {
						// 不满足构造条件
						if (mark[i + 2])nex[i] = i + 2;
						else nex[i] = nex[i + 2];
						mark[i] = 1;
					}
				}
			}
			else {
				// 峰 谷 峰
				if (i & 1) {
					if (a[i] > a[i + 1]) {
						// 满足构造条件
						if (mark[i + 1])nex[i] = i + 1;
						else nex[i] = nex[i + 1];
					}
					else {
						// 不满足构造条件
						if (mark[i + 2])nex[i] = i + 2;
						else nex[i] = nex[i + 2];
						mark[i] = 1;
					}
				}
				else {
					if (a[i] >= a[i + 1]) {
						// 不满足构造条件
						if (mark[i + 2])nex[i] = i + 2;
						else nex[i] = nex[i + 2];
						mark[i] = 1;
					}
					else {
						// 满足构造条件
						if (mark[i + 1])nex[i] = i + 1;
						else nex[i] = nex[i + 1];
					}
				}
			}
		}

		// 处理 k = 0
		int ans = 0;
		fa(i, 1, n)if (!mark[i])ans = max(ans, nex[i] - i + 1);

		const int MAX_LOG = 25;
		var dp = Vec2<int>(n + 1, MAX_LOG + 1);
		fa(i, 1, n) {
			if (mark[i])dp[i][0] = nex[i]; 
			else dp[i][0] = nex[nex[i]]; // 0 先跳到关键点，再花费一次(2^0)超能力跳到下一个关键点
		}

		fa(p, 1, MAX_LOG)
			fa(i, 1, n) {
			if (dp[i][p - 1] == n)dp[i][p] = n;
			else dp[i][p] = dp[dp[i][p - 1]][p - 1];
		}

		fa(i, 1, n) {
			int pos = i;
			fa(p, 0, MAX_LOG) {
				if (k & (1 << p)) {
					pos = dp[pos][p];
					if (pos == n)break;
				}
			}
			ans = max(ans, pos - i + 1);
		}

		return ans;
		};

	cout << max(f(0), f(1)) << endl;
